03AQHx-7ieADvhFQ/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1662867637129?e=1778112000&v=beta&t=nxafPPBJr-_tX8w1aPtV5TdknFbBqVxHY-M8orLCG5M", "peopleAlsoViewed/23/public_identifier": "luciano-lillus-04b1b3b", "peopleAlsoViewed/23/url": "https://linkedin.com/in/ACoAAAH8i3sB69yITb4w_6l7JynBF7ZamOVbJk0", "peopleAlsoViewed/24/entity_urn": "urn:li:fsd_profile:ACoAAAB3DgoB8Hyf1rOsKTiMhFjWmXQR0eL6qWg", "peopleAlsoViewed/24/first_name": "Ross", "peopleAlsoViewed/24/follower_count": "3536", "peopleAlsoViewed/24/headline": "General Manager at Andaz One Bangkok", "peopleAlsoViewed/24/last_name": "Cooper", "peopleAlsoViewed/24/premium": "false", "peopleAlsoViewed/24/profile_picture": "https://media.licdn.com/dms/image/v2/C5603AQE0JzA4evqNGg/profile-displayphoto-shrink_400_400/profile-displayphoto-shrink_400_400/0/1516281874754?e=1778112000&v=beta&t=IN53dkSL28k5oa6uTASnYJlW0PG4jbVwpfkTp9vP2iM", "peopleAlsoViewed/24/public_identifier": "ross-cooper-3227432", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAAAB3DgoB8Hyf1rOsKTiMhFjWmXQR0eL6qWg", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAACFp2hoBJDg7CxmzJo9pFVMOjPzeIEVfiDg", "peopleAlsoViewed/25/first_name": "Opas", "peopleAlsoViewed/25/follower_count": "852", "peopleAlsoViewed/25/headline": "Director of Sales - Leisure & MICE at Lancaster Bangkok", "peopleAlsoViewed/25/last_name": "Jaidet", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/C5603AQFrm06jhixO8g/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1595307304086?e=1778112000&v=beta&t=r-JusYwyZSPdiL_ldsXJ-Rw9278kfxArQJ3lynB_ATk", "peopleAlsoViewed/25/public_identifier": "opas-jaidet-90a8a4137", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAACFp2hoBJDg7CxmzJo9pFVMOjPzeIEVfiDg", "profilePic": "https://media.licdn.com/dms/image/v2/C4D03AQHAzkfvYSDY1w/profile-displayphoto-shrink_400_400/profile-displayphoto-shrink_400_400/0/1516562882715?e=1778112000&v=beta&t=KpDVl_LFsdGYOz7_BYvKfvCAK8IX3AZXUUMnH8hQsxw", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/C4D03AQHAzkfvYSDY1w/profile-displayphoto-shrink_400_400/profile-displayphoto-shrink_400_400/0/1516562882715?e=1778112000&v=beta&t=KpDVl_LFsdGYOz7_BYvKfvCAK8IX3AZXUUMnH8hQsxw", "publicIdentifier": "martin-hurley", "recommendations/0/context": "Martin worked with Nicola on the same team", "recommendations/0/date": "December 31, 2018", "recommendations/0/description": "Nicola is one of the finest HR professionals that I have had the pleasure of working with. Whilst at Lancaster Landmark group in London we completed a variety of HR related projects together, mainly around people development and growing a future pipeline. I found her to be extremely driven, tenacious and using empathy in her decision making, genuinely seeing the importance of team members at all levels.\nNicola has a proven track record in corporate chain hotels and high quality independent properties, and has demonstrated success in both. She is someone I would always turn to for HR policy guidance and her broad experience makes her advice consistently invaluable. Nicola takes a highly structured approach to the development of her own team, and acts as a mentor for up and coming HR specialists. \nWith her knowledge, experience, attitude and drive I view Nicola as one of London’s top Hotel HRD’s.\n\nMartin Hurley\nGeneral Manager\nLancaster Bangkok", "recommendations/0/name": "Nicola Forshaw Chartered FCIPD FIH", "recommendations/0/subtitle": "Group Director of Talent and Culture", "recommendations/0/url": "https://www.linkedin.com/in/nicola-forshaw-chartered-fcipd-fih/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAAFTZaEBpmk9gzRifyAlkMgrfoOBMG7aOo4", "recommendations/1/context": "Martin was Stephen's client", "recommendations/1/date": "March 25, 2016", "recommendations/1/description": "Stephen conducted Up-selling Training for our Guest service Team members in both Reception and Food & Beverage. Multiple sessions were delivered, making it really easy to schedule attendance around our business requirements – Stephen’s flexibility in working around the business was the key to making it happen.\n\nBesides Stephen obvious passion for training and developing people, his Hotel experience ensures that he relates well with delegates and the examples he uses are 100% relevant to the subject matter. This was extremely important to me; I have attended several disengaging training courses that use dull sporting analogies to appeal to a wider group. Having an ex Hotelier who fully understands the day-to-day challenges adds a real element of authenticity and definitely aids learning.\n\nTeam motivation really increased after the training days; there was a real buzz in the air and a desire to put the learning’s into action. Whilst still early days, the training is starting to show real results in increased sales; we just had an all-time record revenue month and I do attribute part of this to the additional upselling that the Team feel equipped to deliver. I would recommend Stephen to anyone looking to enhance their teams sales skills and general levels of motivation and engagement.” \n\nMartin Hurley (General Manager - K West Hotel & Spa)\n", "recommendations/1/name": "Stephen Luck", "recommendations/1/subtitle": "HR Business Partner at Park Plaza Hotels", "recommendations/1/url": "https://www.linkedin.com/in/stephenluckcoaching/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAAOP0uYB_q_mw9Wg4kzgcb9K4Ur1ne6U_YM", "recommendations/2/context": "Martin was Gary's client", "recommendations/2/date": "February 4, 2016", "recommendations/2/description": "Gary Churton has been working with myself and my management team at the K West Hotel & Spa on a Leadership Development course. The first thing that impressed me with Gary was his ability to listen to my objectives and convert them into a tangible and compelling six module course .\n\nBesides Gary’s obvious passion for the training and development, his past Hotel experience ensures that he relates well with delegates and speaks our language. Having an ex Hotelier who fully understands the day to day challenges adds a real element of authenticity and definitely aids learning. Another skill of Gary’s is making sure all the delegates are fully on board and enthused by the subjects; he takes the temperature of the room well and quickly adapts the sessions to match the requirements.\n\nAs the course continues, there is a real buzz in the air and a desire to put the learnings into action. It is no coincidence that Guest satisfaction, Team engagement and inter department relationships have improved since we started the programme. Gary has recently commenced on a similar course with my supervisory Team, and I’m sure it will also give great outcomes.\n\n I would recommend Gary Churton to anyone looking to raise the game of their Team and increase the general levels of motivation and engagement throughout their business.\n", "recommendations/2/name": "Gary Churton", "recommendations/2/subtitle": "Leadership Team Coach, Facilitator and Guest Speaker", "recommendations/2/url": "https://www.linkedin.com/in/gary-churton-b5b3617/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAAAFMRzcBIKbpaq3bIE5xMRyI3NtKTuJVmOo", "recommendations/3/context": "Martin was senior to David but didn't manage David directly", "recommendations/3/date": "November 3, 2014", "recommendations/3/description": "During my time working with David, I was always impressed with his tenacity and desire to make positive change. David could never be accused of \"going with the flow\", he would always positively challenge decisions that impact the Guest experience - which is never easy to do in a big brand. If I could single out one thing that sets David apart is his approach to Team development. This is a huge focus of his; the difference with David compared to many of his peers is that he does this genuinely to help his Teams grow - not to boost his own profile. David is a very entrepreneurial GM, with a keen eye for quality and a \"Gung Ho\" drive for results. I would definitely recommend David for any role\nthat required these attributes.\n\nMartin Hurley\nGeneral Manager\nK West Hotel & Spa", "recommendations/3/name": "David Groves MTPI", "recommendations/3/subtitle": "Managing Director- West End Quay - building a Self Manage model for Large Residential blocks of homes.", "recommendations/3/url": "https://www.linkedin.com/in/davidgroves71/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAAKcKgkB679VO7ogULzvpcrcnCnC3HMYiKw", "recommendations/4/context": "Martin was Emma's client", "recommendations/4/date": "September 7, 2011", "recommendations/4/description": "Emma is a first rate consultant, possibly the best I have ever worked with in this field. Her knowledge is second to none, and she excels in coaching and interpersonal skills. I would not hesitate to recommend her work. I have worked with Emma since 2003, and hope to work with her again in the future.", "recommendations/4/name": "Emma Noble", "recommendations/4/subtitle": "GuestPath® Business Partner", "recommendations/4/url": "https://www.linkedin.com/in/emma-noble-1980001/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAAtkQQBHP7gamxFHxrx-T9Jp30dHt-ne6E", "skills/0/title": "Hotel Management", "skills/1/title": "Revenue Analysis", "skills/2/title": "Hospitality Management", "skills/3/title": "Hotels", "skills/4/title": "Hospitality Industry", "skills/5/title": "Hospitality", "skills/6/title": "Yield Management", "skills/7/title": "Food & Beverage", "skills/8/title": "Leisure", "skills/9/title": "Tourism", "skills/10/title": "Pre-opening", "skills/11/title": "Property Management Systems", "skills/12/title": "Rooms Division", "skills/13/title": "Restaurants", "skills/14/title": "Event Management", "skills/15/title": "Catering", "skills/16/title": "Customer Satisfaction", "skills/17/title"